module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);
    reg [7:0] dividend_temp;
    reg [7:0] divisor_temp;
    reg [8:0] sr;
    reg [7:0] remainder;
    reg [7:0] quotient;
    reg [2:0] cnt;
    reg start_cnt;
    reg [8:0] neg_divisor;
    reg carry_out;
    reg temp;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            dividend_temp <= 8'd0;
            divisor_temp <= 8'd0;
            sr <= 9'd0;
            remainder <= 8'd0;
            quotient <= 8'd0;
            cnt <= 3'd0;
            start_cnt <= 1'b0;
            neg_divisor <= 9'd0;
            carry_out <= 1'b0;
            temp <= 1'b0;
            res_valid <= 1'b0;
            result <= 16'd0;
        end else begin
            if (opn_valid && !res_valid) begin
                dividend_temp <= dividend;
                divisor_temp <= divisor;
                sr <= {1'b0, dividend_temp};

                if (sign) begin
                    neg_divisor <= ~divisor_temp + 1;
                end else begin
                    neg_divisor <= divisor_temp;
                end

                cnt <= 3'd1;
                start_cnt <= 1'b1;
            end

            if (start_cnt) begin
                if (cnt == 3'd8) begin
                    cnt <= 3'd0;
                    start_cnt <= 1'b0;

                    remainder <= sr[7:0];
                    quotient <= sr[15:8];

                    result <= {remainder, quotient};
                    res_valid <= 1'b1;
                end else begin
                    {carry_out, temp} <= sr - neg_divisor;
                    sr <= {temp[7], sr[8:1]};
                    sr[0] <= carry_out;
                    cnt <= cnt + 1;
                end
            end
        end
    end

    always @(posedge clk) begin
        if (rst) begin
            res_valid <= 1'b0;
        end else begin
            if (cnt == 3'd8) begin
                res_valid <= 1'b1;
            end else if (res_valid && res_ready) begin
                res_valid <= 1'b0;
            end
        end
    end
endmodule

