<module id="div_8bit">
    <description>Implement a simplified radix-2 divider on 8-bit signed or unsigned integers. Accepts a dividend and a divisor as inputs and provides a 16-bit result containing both the quotient and the remainder. Supports both signed and unsigned division operations.</description>
    <ports>
        <input id="clk">Clock signal used for synchronous operation.</input>
        <input id="rst">The reset signal to initialize or reset the module.</input>
        <input id="sign">1-bit indicates if the operation is signed (1) or unsigned (0).</input>
        <input id="dividend" width_description="[7:0]">8-bit input signal representing the dividend for division.</input>
        <input id="divisor" width_description="[7:0]">8-bit input signal representing the divisor for division.</input>
        <input id="opn_valid">1-bit indicates that a valid operation request is present.</input>
        <input id="res_ready">1-bit indicates that the 16-bit output result has already been acknowledged.</input>
        <output id="res_valid">1-bit output signal indicating the result is valid and ready.</output>
        <output id="result" width_description="[15:0]">16-bit the output containing the remainder in the upper 8 bits and the quotient in the lower 8 bits.</output>
    </ports>
    <parameter_description>
        <state name="IDLE" value="2'b00"/>
        <state name="DIVIDE" value="2'b01"/>
        <state name="DONE" value="2'b10"/>
    </parameter_description>
    <logic_description type="sequential_logic">
        <reg id="state" width="2" init_value="IDLE">State machine state.</reg>
        <reg id="cnt" width="3" init_value="0">Counter for division iterations.</reg>
        <reg id="start_cnt" width="1" init_value="0">Flag to indicate start of division process.</reg>
        <reg id="neg_divisor" width="9" init_value="0">Negated divisor for subtraction.</reg>
        <reg id="sr" width="9" init_value="0">Shift register for storing partial results.</reg>
        <reg id="remainder" width="8" init_value="0">Final remainder after division.</reg>
        <reg id="quotient" width="8" init_value="0">Final quotient after division.</reg>
        <reg id="res_valid_reg" width="1" init_value="0">Register to manage result validity.</reg>
    </logic_description>
    <implementation>
        // Initialize registers on reset
        always @(posedge clk or posedge rst) begin
            if (rst) begin
                state <= IDLE;
                cnt <= 0;
                start_cnt <= 0;
                neg_divisor <= 0;
                sr <= 0;
                remainder <= 0;
                quotient <= 0;
                res_valid_reg <= 0;
            end else begin
                case (state)
                    IDLE: begin
                        if (opn_valid && !res_valid_reg) begin
                            // Save inputs
                            dividend_temp <= dividend;
                            divisor_temp <= divisor;
                            // Initialize shift register
                            sr <= {1'b0, dividend_temp};
                            // Negate divisor if signed
                            if (sign) begin
                                neg_divisor <= ~divisor_temp + 1;
                            end else begin
                                neg_divisor <= divisor_temp;
                            end
                            // Set flags
                            cnt <= 1;
                            start_cnt <= 1;
                            state <= DIVIDE;
                        end
                    end
                    DIVIDE: begin
                        if (start_cnt) begin
                            if (cnt[2]) begin
                                // Division complete
                                cnt <= 0;
                                start_cnt <= 0;
                                state <= DONE;
                            end else begin
                                // Perform subtraction
                                {carry_out, temp} <= sr - neg_divisor;
                                // Update shift register
                                sr <= {temp[7], sr[8:1]};
                                // Shift in carry-out
                                sr[0] <= carry_out;
                                // Increment counter
                                cnt <= cnt + 1;
                            end
                        end
                    end
                    DONE: begin
                        // Finalize results
                        remainder <= sr[7:0];
                        quotient <= sr[15:8];
                        state <= IDLE;
                    end
                endcase
            end
        end

        // Manage result validity
        always @(posedge clk) begin
            if (rst) begin
                res_valid_reg <= 0;
            end else begin
                if (cnt == 8) begin
                    res_valid_reg <= 1;
                end else if (res_valid_reg && res_ready) begin
                    res_valid_reg <= 0;
                end
            end
        end
    </implementation>
</module>
